	workerRunId: string;
	outcome: IntakeCuratorDecision;
	nextAction?: string;
	shouldStartBuilder: boolean;
};

export type IntakeCuratorInput = {
	workItemId: string;
	workItem: GitHubProjectIssueWorkItem;
	runId?: string | null;
	attemptId?: string | null;
};

export type PostPrCuratorInput = {
	workItemId: string;
	workItem: GitHubProjectIssueWorkItem;
	pullRequestUrl: string;
	pullRequestNumber: number;
	owner: string;
	repository: string;
};

export type PostPrCuratorResult = {
	workItemId: string;
	workerRunId: string;		decId: string;
	pullRequestCheck: PullRequestCheckSummary;
	determination: PullRequestCheckClassification;
};

export async function runIntakeCurator(input: IntakeCuratorInput): Promise<IntakeCuratorResult> {
	const buildable = isIntakeBuildable(input.workItem);
	const outcome: IntakeCuratorDecision = buildable ? "buildable" : "ask_human";
	const nextAction = buildable
		? null
		: "Please add a non-empty title and body describing expected output before dispatch.";

	const workerRun = await createWorkerRun({
		workItemId: input.workItemId,
		kind: "intake_curator",
		status: "completed",
		metadata: {
			issueTitle: input.workItem.issueTitle,
			issueBody: input.workItem.issueBody,
			issueNumber: input.workItem.issueNumber,
		},
	});

	const decision = await createDecision({
		workItemId: input.workItemId,
		workerRunId: workerRun.id,
		phase: "intake",
		outcome,
		deterministic: true,
		nextWorkerKind: buildable ? "builder" : null,
		nextAction,
		evidence: {
			issueTitle: input.workItem.issueTitle,
			issueBodyPreview: input.workItem.issueBody?.slice(0, 120) ?? null,
			issueNumber: input.workItem.issueNumber,
		},
	});

	await updateWorkerRunStatus({
		id: workerRun.id,
		status: "completed",
	});

	if (input.runId && input.attemptId) {
		await createEventProxy({
			workItemId: input.workItemId,
			decisionId: decision,
			workerRunId: workerRun.id,
			runId: input.runId,
			attemptId: input.attemptId,
		});
	}

	return {
		workItemId: input.workItemId,
		decisionId: decision,
		workerRunId: workerRun.id,
		outcome,
		nextAction: nextAction ?? undefined,
		shouldStartBuilder: buildable,
	};
}

export async function runPostPrCurator(
	input: PostPrCuratorInput,
): Promise<PostPrCuratorResult> {
	const pullRequestCheck = await getPullRequestCheckSummary({
		owner: input.owner,
		repository: input.repository,
		pullRequestNumber: input.pullRequestNumber,
	});

	const workerRun = await createWorkerRun({
		workItemId: input.workItemId,
		kind: "post_pr_curator",
		status: "completed",
		metadata: {
			issueNumber: input.workItem.issueNumber,
			pullRequestNumber: input.pullRequestNumber,
			pullRequestUrl: input.pullRequestUrl,
		},
	});

	const decision = await createDecision({
